const crypto = require('crypto');
const secret = 'Some hard to guess text here.'; // replace with your own secret
const passHash = new Promise(resolve => {
  const iterations = 10; // higher value means more secure, but also longer time to create a password.
  const keyLength = 64;

  const salt = crypto.randomBytes(keyLength / 2);
  crypto.pbkdf2(secret, salt, iterations, keyLength, 'sha512', function(err, derivedKey) {
    resolve({salt, derivedKey});
  });
});